25	export function createQuote(items: unknown[]): number {
26	  const quoteItems = items as QuoteItem[];
27	  if (quoteItems.length === 0) {
28	    return PROCESSING_FEE;
29	  }
30	  const totalPremium = quoteItems.reduce((sum, item) => {
31	    const basePremium = getItemBasePremium(item.type);
32	    if (basePremium === undefined) {
33	      throw new Error(`Unknown item type: ${item.type}`);
34	    }
35	    return sum + basePremium;
36	  }, 0);
37	  return totalPremium + PROCESSING_FEE;
